import api from "./api";

export const createOrder = ({ items, notes = "", payment_method = "demo", answers = [] }) => {
  return api.post("/users/orders", {
    items,
    notes,
    payment_method,
    answers,
  });
};

export const getMyOrders = (params = {}) => {
  return api.get("/users/orders", { params });
};

export const getOrderDetail = (orderId) => {
  return api.get(`/users/orders/${orderId}`);
};

export const cancelOrder = (orderId, cancel_reason = "") => {
  return api.put(`/users/orders/${orderId}/cancel`, { cancel_reason });
};
